import create from 'zustand';

/**
 * State management for Omega Reality feature using Zustand.
 */
const useOmegaRealityStore = create((set) => ({
    realityData: null,
    verificationStatus: null,
    setRealityData: (data) => set({ realityData: data }),
    setVerificationStatus: (status) => set({ verificationStatus: status }),
}));

/**
 * Fetch reality synthesis data from the server.
 * @returns {Promise<Object|null>} The synthesized reality data or null if an error occurs.
 */
export async function fetchRealitySynthesis() {
    try {
        const response = await fetch('http://localhost:3001/reality-synthesis');
        if (!response.ok) {
            throw new Error('Failed to fetch reality synthesis');
        }
        const data = await response.json();
        useOmegaRealityStore.getState().setRealityData(data);
        return data;
    } catch (error) {
        console.error('Error fetching reality synthesis:', error);
        return null;
    }
}

/**
 * Verify the truth of the synthesized reality.
 * @param {Object} realityData - The synthesized reality data to verify.
 * @returns {Promise<string|null>} The verification status or null if an error occurs.
 */
export async function verifyReality(realityData) {
    try {
        const response = await fetch('http://localhost:3001/verify-reality', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(realityData),
        });
        if (!response.ok) {
            throw new Error('Failed to verify reality');
        }
        const result = await response.json();
        useOmegaRealityStore.getState().setVerificationStatus(result.status);
        return result.status;
    } catch (error) {
        console.error('Error verifying reality:', error);
        return null;
    }
}

/**
 * Fetch AI-driven insights based on the current reality data.
 * @param {Object} realityData - The reality data to get insights for.
 * @returns {Promise<Object|null>} The AI insights or null if an error occurs.
 */
export async function fetchAIInsights(realityData) {
    try {
        const response = await fetch('http://localhost:3001/chat', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({ prompt: realityData }),
        });
        if (!response.ok) {
            throw new Error('Failed to fetch AI insights');
        }
        const insights = await response.json();
        return insights;
    } catch (error) {
        console.error('Error fetching AI insights:', error);
        return null;
    }
}

/**
 * Retrieve current state of reality.
 * @returns {Object|null} The current reality data or null if not set.
 */
export function getCurrentReality() {
    return useOmegaRealityStore.getState().realityData;
}

/**
 * Retrieve the current verification status.
 * @returns {string|null} The current verification status or null if not set.
 */
export function getVerificationStatus() {
    return useOmegaRealityStore.getState().verificationStatus;
}

export {
    useOmegaRealityStore,
    fetchRealitySynthesis,
    verifyReality,
    fetchAIInsights,
    getCurrentReality,
    getVerificationStatus,
};